// Extract top trending posts or use fallback
const items = $input.all();
const xData = items[0]?.json;

let trendingRef = '';

if (xData && xData.data && xData.data.length > 0) {
  // Sort by engagement
  const tweets = xData.data.sort((a, b) => {
    const engA = (a.public_metrics?.like_count || 0) + (a.public_metrics?.reply_count || 0) * 3;
    const engB = (b.public_metrics?.like_count || 0) + (b.public_metrics?.reply_count || 0) * 3;
    return engB - engA;
  });

  const top3 = tweets.slice(0, 3).map(t => t.text.substring(0, 150)).join(' | ');
  trendingRef = `Top X trends today: ${top3}`;
} else {
  // Fallback trend data (update weekly)
  const fallbacks = [
    'Golden hour travel portraits dominating X. Beach and terrace silhouette shots getting 4-6x engagement. Bali and Greece top performing locations.',
    'Tokyo night aesthetic trending hard. Neon reflections on wet streets + candid fashion = viral formula. Cyberpunk-adjacent but grounded.',
    'Philippines travel content surging. Palawan and Siargao driving strong diaspora engagement across X and Threads.',
    'Cherry blossom season driving massive Japan travel content engagement. Soft pink + white aesthetic performing 3x above average.',
    'Paris cafe morning aesthetic trending. "Quiet girl" and "soft life" lifestyle content consistently high saves and shares.',
  ];
  const dayOfYear = Math.floor((new Date() - new Date(new Date().getFullYear(), 0, 0)) / 86400000);
  trendingRef = fallbacks[dayOfYear % fallbacks.length];
}

console.log('Trending reference:', trendingRef);
return [{ json: { trending_reference: trendingRef } }];

// Parse Claude's JSON response
const raw = $input.first().json.text || $input.first().json.content || '';

let postData;
try {
  // Remove markdown code blocks if present
  let cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  postData = JSON.parse(cleaned);
} catch (e) {
  console.error('Failed to parse Claude response:', raw.substring(0, 500));
  throw new Error('Claude returned invalid JSON. Check the Generate Prompt node.');
}

if (!postData.prompt) throw new Error('No prompt in Claude response');

console.log('Generated post:', postData.title);
console.log('Platform:', postData.platform);
console.log('Prompt preview:', postData.prompt.substring(0, 150));

return [{ json: postData }];

// Extract image URL from Freepik response
const data = $input.first().json;

let imageUrl = '';

// Handle direct response
if (data.data && Array.isArray(data.data) && data.data[0]?.url) {
  imageUrl = data.data[0].url;
} else if (data.data?.generated?.[0]?.url) {
  imageUrl = data.data.generated[0].url;
} else if (data.url) {
  imageUrl = data.url;
}

if (!imageUrl && data.data?.task_id) {
  // Async task - need polling (handle in a separate polling sub-workflow or use wait node)
  console.log('Freepik async task ID:', data.data.task_id);
  imageUrl = `PENDING_TASK:${data.data.task_id}`;
}

if (!imageUrl) {
  console.error('Could not extract image URL from Freepik response:', JSON.stringify(data).substring(0, 300));
  imageUrl = 'https://images.unsplash.com/photo-1537996194471-e657df975ab4?w=600&auto=format&fit=crop';
}

// Get the post data from earlier in the workflow
const postData = $('Parse Claude Response').first().json;
postData.image = imageUrl;

console.log('Image URL:', imageUrl);
return [{ json: postData }];

// For non-Freepik platforms: prepare post data with empty image
// A notification will be sent to remind you to manually generate
const postData = $input.first().json;
postData.image = '';
postData.manual_generation_required = true;
return [{ json: postData }];

// Merge both branches
const postData = $input.first().json;
return [{ json: postData }];

const githubResponse = $input.first().json;
const newPost = $('Merge Post Data').first().json;

// Decode current posts.json from base64
let currentData;
try {
  const decoded = Buffer.from(githubResponse.content.replace(/\n/g, ''), 'base64').toString('utf-8');
  currentData = JSON.parse(decoded);
} catch(e) {
  currentData = {
    last_updated: '',
    influencer: { name: 'Nova Linh', handle: '@novalinhofficial' },
    posts: []
  };
}

// Check for duplicate
const exists = currentData.posts.some(p => p.id === newPost.id);
if (exists) {
  throw new Error(`Post ${newPost.id} already exists. Skipping.`);
}

// Prepend new post
currentData.posts.unshift(newPost);
currentData.last_updated = new Date().toISOString().split('T')[0];

// Encode to base64
const updatedJson = JSON.stringify(currentData, null, 2);
const encoded = Buffer.from(updatedJson).toString('base64');

return [{
  json: {
    sha: githubResponse.sha,
    content: encoded,
    post_title: newPost.title,
    post_id: newPost.id,
    manual_required: newPost.manual_generation_required || false
  }
}];

const commitResult = $input.first().json;
const buildData = $('Build GitHub Commit').first().json;

// Log success
console.log('===== NOVA LINH DAILY POST PUBLISHED =====');
console.log('Post:', buildData.post_title);
console.log('ID:', buildData.post_id);
console.log('Manual generation needed:', buildData.manual_required);
console.log('GitHub commit:', commitResult.commit?.sha?.substring(0, 8));
console.log('Netlify deploying... (check in ~60s)');

return [{
  json: {
    success: true,
    post_title: buildData.post_title,
    post_id: buildData.post_id,
    manual_generation_required: buildData.manual_required,
    commit_sha: commitResult.commit?.sha?.substring(0, 8),
    timestamp: new Date().toISOString()
  }
}];
